import{_ as t,o,c as a,ag as r}from"./chunks/framework.Bo7atV7P.js";const h=JSON.parse('{"title":"Glossary","description":"","frontmatter":{},"headers":[],"relativePath":"glossary.md","filePath":"glossary.md","lastUpdated":1776245656000}'),s={name:"glossary.md"};function c(d,e,i,n,p,l){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="glossary" tabindex="-1">Glossary <a class="header-anchor" href="#glossary" aria-label="Permalink to &quot;Glossary&quot;">​</a></h1><h2 id="hook" tabindex="-1">hook <a class="header-anchor" href="#hook" aria-label="Permalink to &quot;hook&quot;">​</a></h2><p>A bash script (or directory of scripts) placed in <code>scripts/hooks/</code> that the setup runtime executes at a specific lifecycle point. Hooks extend setup behavior without modifying shared runtime code. See <a href="./guides/overriding-setup.html">Overriding Setup Scripts</a>.</p><h2 id="project-owned-path" tabindex="-1">project-owned path <a class="header-anchor" href="#project-owned-path" aria-label="Permalink to &quot;project-owned path&quot;">​</a></h2><p>A file or directory that belongs to the consuming project, not to the shared <code>setup-core</code> runtime. Project-owned paths are never overwritten by <code>webentor-setup upgrade-starter</code>. The current list:</p><ul><li><code>scripts/.env.setup</code></li><li><code>scripts/hooks/</code></li><li><code>scripts/project-specific/</code></li></ul><h2 id="setup-core" tabindex="-1">setup-core <a class="header-anchor" href="#setup-core" aria-label="Permalink to &quot;setup-core&quot;">​</a></h2><p>The shared setup runtime that lives in <code>scripts/setup-core/</code> inside a project. It is added via <code>git subtree add</code> from a tagged <code>webentor-setup</code> release during project init and should <strong>not</strong> be edited directly. Update it by pulling a new tag with <code>git subtree pull</code>.</p><h2 id="setup-metadata" tabindex="-1">setup metadata <a class="header-anchor" href="#setup-metadata" aria-label="Permalink to &quot;setup metadata&quot;">​</a></h2><p>The <code>.webentor/project.json</code> file at the project root. It is created by <code>webentor-setup init</code> and updated by <code>webentor-setup upgrade-starter</code>. It records which versions of the stack a project is using and stores setup-time configuration like <code>withDbSync</code> and <code>withTypesense</code>.</p><h2 id="setup-runtime" tabindex="-1">setup runtime <a class="header-anchor" href="#setup-runtime" aria-label="Permalink to &quot;setup runtime&quot;">​</a></h2><p>The combination of <code>scripts/setup-core/setup.sh</code> and platform-specific scripts (<code>mac/mac.sh</code>, <code>win/win.sh</code>, etc.) that orchestrate a full environment setup. Also referred to as &quot;setup-core runtime&quot;.</p><h2 id="setup-scaffolding" tabindex="-1">setup scaffolding <a class="header-anchor" href="#setup-scaffolding" aria-label="Permalink to &quot;setup scaffolding&quot;">​</a></h2><p>The generated files outside <code>setup-core</code> that <code>webentor-setup init</code> creates: <code>scripts/.env.setup</code>, <code>scripts/setup.sh</code>, <code>scripts/hooks/</code>, <code>scripts/project-specific/</code>, and optionally <code>scripts/ts-up.sh</code> and <code>scripts/docker-compose.typesense.yml</code>. These are project-owned and not part of the subtree.</p><h2 id="upgrade-manifest" tabindex="-1">upgrade manifest <a class="header-anchor" href="#upgrade-manifest" aria-label="Permalink to &quot;upgrade manifest&quot;">​</a></h2><p>A <code>manifest.json</code> file inside <code>scripts/setup-core/upgrades/&lt;version&gt;/</code> that describes a set of deterministic transforms (text replacements, path deletions, directory creations) to apply during a <code>webentor-setup upgrade-starter</code> run.</p><h2 id="webentor-core" tabindex="-1">webentor-core <a class="header-anchor" href="#webentor-core" aria-label="Permalink to &quot;webentor-core&quot;">​</a></h2><p>The shared PHP + JavaScript runtime package (<code>@webikon/webentor-core</code>). It provides reusable block utilities, image helpers, Alpine.js components, and WordPress filters. Published to both npm (GitHub Packages) and Composer.</p><h2 id="webentor-configs" tabindex="-1">webentor-configs <a class="header-anchor" href="#webentor-configs" aria-label="Permalink to &quot;webentor-configs&quot;">​</a></h2><p>The centralized lint and formatting preset package (<code>@webikon/webentor-configs</code>). Provides shared ESLint, Stylelint, Prettier, PHPCS, and Blade formatter configs.</p><h2 id="webentor-setup" tabindex="-1">webentor-setup <a class="header-anchor" href="#webentor-setup" aria-label="Permalink to &quot;webentor-setup&quot;">​</a></h2><p>The package that contains the <code>setup-core</code> runtime (bash scripts + PHP CLI). Published as a standalone GitHub repository and consumed via <code>git subtree</code>. The <code>init</code> command generates all project scaffolding (<code>scripts/</code>, <code>.webentor/</code>) from CLI flags.</p><h2 id="webentor-starter" tabindex="-1">webentor-starter <a class="header-anchor" href="#webentor-starter" aria-label="Permalink to &quot;webentor-starter&quot;">​</a></h2><p>The WordPress project skeleton template. Built on Bedrock + Sage 10. Contains only the WordPress/theme structure — all setup scaffolding is added via <code>git subtree add</code> (for <code>setup-core</code>) and <code>webentor-setup init</code> (for generated files).</p>',24)])])}const b=t(s,[["render",c]]);export{h as __pageData,b as default};
